'use client';

import React from 'react';
import { msg, useMessages } from 'gt-next';
import { useGame } from '@/context/GameContext';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Card } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { ScrollArea } from '@/components/ui/scroll-area';
import {
  AdvisorIcon,
  InfoIcon,
  PowerIcon,
  WaterIcon,
  MoneyIcon,
  SafetyIcon,
  HealthIcon,
  EducationIcon,
  EnvironmentIcon,
  JobsIcon,
} from '@/components/ui/Icons';

// Translatable UI labels
const UI_LABELS = {
  cityAdvisors: msg('Investment Committee Briefing'),
  overallCityRating: msg('Fund Operating Score'),
  ratingDescription: msg('Based on PMF, growth momentum, burn discipline, confidence, hiring velocity'),
  noUrgentIssues: msg('No urgent portfolio risks right now.'),
  cityRunningSmoothly: msg('Fund operations are stable this month.'),
};

const ADVISOR_ICON_MAP: Record<string, React.ReactNode> = {
  power: <PowerIcon size={18} />,
  water: <WaterIcon size={18} />,
  cash: <MoneyIcon size={18} />,
  shield: <SafetyIcon size={18} />,
  hospital: <HealthIcon size={18} />,
  education: <EducationIcon size={18} />,
  environment: <EnvironmentIcon size={18} />,
  planning: <AdvisorIcon size={18} />,
  jobs: <JobsIcon size={18} />,
};

export function AdvisorsPanel() {
  const { state, investorSession, setActivePanel } = useGame();
  const { stats, competitionDegree } = state;
  const m = useMessages();

  const clampPercent = (value: number) => Math.max(0, Math.min(100, Math.round(value)));
  const demand = {
    residential: stats.demand?.residential ?? 0,
    commercial: stats.demand?.commercial ?? 0,
    industrial: stats.demand?.industrial ?? 0,
  };
  const income = Number.isFinite(stats.income) ? stats.income : 0;
  const expenses = Number.isFinite(stats.expenses) ? stats.expenses : 0;
  const dryPowder = investorSession ? investorSession.stats.dryPowder : stats.money;
  const netBurn = investorSession ? investorSession.stats.netBurn : income - expenses;
  const runwayMonths = investorSession
    ? investorSession.stats.runwayMonths
    : expenses > 0
      ? Math.max(0, dryPowder / expenses)
      : 99;
  const dealFlow = investorSession
    ? investorSession.stats.dealFlow
    : Math.max(0, Math.round((demand.commercial + demand.industrial + 220) / 28));

  const pmfSignal = investorSession
    ? clampPercent(investorSession.stats.pmfSignalPercentile)
    : clampPercent(stats.happiness * 0.45 + stats.education * 0.25 + ((demand.commercial + 100) / 2) * 0.2 + 8);
  const growthMomentum = investorSession
    ? clampPercent(investorSession.stats.growthMomentumPercentile)
    : clampPercent(((income - expenses) / Math.max(Math.abs(income), 1)) * 35 + 50 + demand.commercial * 0.15 + 10);
  const burnDiscipline = investorSession
    ? clampPercent(investorSession.stats.burnDisciplinePercentile)
    : clampPercent(100 - (income > 0 ? expenses / income : expenses > 0 ? 3 : 1) * 30 + 9);
  const investorConfidence = investorSession
    ? clampPercent(investorSession.stats.investorConfidencePercentile)
    : clampPercent((dryPowder > 0 ? 46 : 30) + demand.commercial * 0.2 + demand.industrial * 0.12 + (income > expenses ? 10 : -6) + 8);
  const hiringVelocity = investorSession
    ? clampPercent(investorSession.stats.hiringVelocityPercentile)
    : clampPercent((stats.jobs / Math.max(stats.population, 1)) * 70 + demand.residential * 0.25 + demand.commercial * 0.12 + 7);

  const avgRating = (pmfSignal + growthMomentum + burnDiscipline + investorConfidence + hiringVelocity) / 5;
  const grade = avgRating >= 90 ? 'A+' : avgRating >= 80 ? 'A' : avgRating >= 70 ? 'B' : avgRating >= 60 ? 'C' : avgRating >= 50 ? 'D' : 'F';
  const gradeColor = avgRating >= 70 ? 'text-green-400' : avgRating >= 50 ? 'text-amber-400' : 'text-red-400';

  type Priority = 'low' | 'medium' | 'high' | 'critical';
  type BriefCard = {
    name: string;
    icon: string;
    priority: Priority;
    messages: string[];
  };
  const cards: BriefCard[] = [];

  if (runwayMonths < 8 || dryPowder < 0 || netBurn < 0) {
    cards.push({
      name: 'Capital Strategy',
      icon: 'cash',
      priority: runwayMonths < 4 || dryPowder < 0 ? 'critical' : 'high',
      messages: [
        `Runway is ${runwayMonths.toFixed(1)} months with dry powder at $${Math.round(dryPowder).toLocaleString()}.`,
        netBurn < 0
          ? `Portfolio burn is $${Math.abs(Math.round(netBurn)).toLocaleString()}/month. Slow burn or close quality follow-ons.`
          : `Net burn is positive. Keep reserve discipline and defend core winners.`,
      ],
    });
  }

  if (pmfSignal < 45 || growthMomentum < 45) {
    cards.push({
      name: 'Portfolio PMF & Growth',
      icon: 'planning',
      priority: pmfSignal < 30 || growthMomentum < 30 ? 'critical' : 'high',
      messages: [
        `PMF signal ${pmfSignal}% and growth momentum ${growthMomentum}% are below target.`,
        'Push offering partnerships and commercial partnerships across portfolio companies to recover momentum.',
      ],
    });
  }

  if (hiringVelocity < 45 || burnDiscipline < 45) {
    cards.push({
      name: 'Talent & Burn Quality',
      icon: 'jobs',
      priority: hiringVelocity < 30 || burnDiscipline < 30 ? 'critical' : 'high',
      messages: [
        `Hiring velocity ${hiringVelocity}% and burn discipline ${burnDiscipline}% need correction.`,
        'Prioritize recruiting support on top performers and freeze non-critical spend in weak clusters.',
      ],
    });
  }

  if (competitionDegree >= 65 || dealFlow < 4 || investorConfidence < 45) {
    cards.push({
      name: 'Competitive Deal Pressure',
      icon: 'shield',
      priority: competitionDegree >= 80 || investorConfidence < 30 ? 'critical' : 'medium',
      messages: [
        `Competition degree is ${Math.round(competitionDegree)}% with deal flow at ${dealFlow}.`,
        investorConfidence < 45
          ? `Investor confidence is ${investorConfidence}%. Rival funds can win rounds unless conviction quality improves.`
          : 'Maintain founder support and move faster on conviction to avoid losing allocations.',
      ],
    });
  }

  if (cards.length === 0) {
    cards.push({
      name: 'Operating Rhythm',
      icon: 'planning',
      priority: 'low',
      messages: ['Signals are stable across PMF, growth, burn, confidence, and hiring.'],
    });
  }
  
  return (
    <Dialog open={true} onOpenChange={() => setActivePanel('none')}>
      <DialogContent className="max-w-[500px] max-h-[600px]">
        <DialogHeader>
          <DialogTitle>{m(UI_LABELS.cityAdvisors)}</DialogTitle>
        </DialogHeader>
        
        <div className="space-y-4">
          <Card className="flex items-center gap-4 p-4 bg-primary/10 border-primary/30">
            <div 
              className={`w-16 h-16 flex items-center justify-center text-3xl font-black rounded-md ${gradeColor} bg-primary/20`}
            >
              {grade}
            </div>
            <div>
              <div className="text-foreground font-semibold">{m(UI_LABELS.overallCityRating)}</div>
              <div className="text-muted-foreground text-sm">{m(UI_LABELS.ratingDescription)}</div>
            </div>
          </Card>
          
          <ScrollArea className="max-h-[350px]">
            <div className="space-y-3">
              {cards.length === 0 ? (
                <Card className="text-center py-8 text-muted-foreground bg-primary/10 border-primary/30">
                  <AdvisorIcon size={32} className="mx-auto mb-3 opacity-50" />
                  <div className="text-sm">{m(UI_LABELS.noUrgentIssues)}</div>
                  <div className="text-xs mt-1">{m(UI_LABELS.cityRunningSmoothly)}</div>
                </Card>
              ) : (
                cards.map((advisor, i) => (
                  <Card key={i} className={`p-3 bg-primary/10 border-primary/30 ${
                    advisor.priority === 'critical' ? 'border-l-2 border-l-red-500' :
                    advisor.priority === 'high' ? 'border-l-2 border-l-amber-500' :
                    advisor.priority === 'medium' ? 'border-l-2 border-l-yellow-500' : ''
                  }`}>
                    <div className="flex items-center gap-2 mb-2">
                      <span className="text-lg text-muted-foreground">
                        {ADVISOR_ICON_MAP[advisor.icon] || <InfoIcon size={18} />}
                      </span>
                      <span className="text-foreground font-medium text-sm">{advisor.name}</span>
                      <Badge 
                        variant={
                          advisor.priority === 'critical' ? 'destructive' :
                          advisor.priority === 'high' ? 'destructive' : 'secondary'
                        }
                        className="ml-auto text-[10px]"
                      >
                        {advisor.priority}
                      </Badge>
                    </div>
                    {advisor.messages.map((msg, j) => (
                      <div key={j} className="text-muted-foreground text-sm leading-relaxed">{msg}</div>
                    ))}
                  </Card>
                ))
              )}
            </div>
          </ScrollArea>
        </div>
      </DialogContent>
    </Dialog>
  );
}
